import { useEffect, useState } from "react";
import { socket } from "./socket";

function Room({ room, name }) {
  const [question, setQuestion] = useState("");
  const [answer, setAnswer] = useState("");
  const [scores, setScores] = useState({});

  useEffect(() => {
    socket.emit("join_room", {
        roomCode: room,
        role: "participant", // или "organizer"
        name: name,
    });

    socket.on("receive_question", (q) => {
      setQuestion(q);
    });

    socket.on("update_scores", (data) => {
        setScores(data);
    });

    socket.on("receive_answer", (a) => {
      console.log("Answer:", a);
    });

    socket.on("quiz_finished", (finalScores) => {
        alert("Квиз закончен!");
        console.log(finalScores);
    });

    return () => {
      socket.off("receive_question");
      socket.off("receive_answer");
    };
  }, [room]);

  const sendQuestion = () => {
    socket.emit("send_question", {
      roomCode: room,
      question: "2+2?",
      correct: "4",
    });
  };

  const sendAnswer = () => {
    socket.emit("submit_answer", {
      roomCode: room,
      answer: answer,
      name: name,
    });
  };


  return (
    <div>
      <h2>Room: {room}</h2>

      <button onClick={sendQuestion}>
        Отправить вопрос (организатор)
      </button>

      {question && (
        <div>
            {question.imageUrl && (
            <img src={question.imageUrl} alt="" width="200" />
            )}

            <h3>{question.text}</h3>

            {question.options?.map((opt, i) => (
            <button key={i} onClick={() => setAnswer(opt)}>
                {opt}
            </button>
            ))}
        </div>
      )}

      <h3>Leaderboard:</h3>
      {Object.entries(scores).map(([user, score]) => (
        <div key={user}>
            {user}: {score}
        </div>
      ))}

      <input
        placeholder="Ваш ответ"
        onChange={(e) => setAnswer(e.target.value)}
      />

      <button onClick={sendAnswer}>
        Ответить
      </button>

      <button
        onClick={() => {
            socket.emit("start_quiz", {
                roomCode: room,
                quizId: 1,
            });
        }}
      >
      Старт квиза
      </button>

      {role === "organizer" && (
        <button
            onClick={() => {
                socket.emit("next_question", {
                roomCode: room,
                });
            }}
        >
            Следующий вопрос
        </button>
      )}
    </div>
  );
}

export default Room;
